const BACKUP_KEY = "st_stream_guard";
const STATE_KEY = "st_stream_guard_state";
const POLL_INTERVAL = 5000;
const DEBOUNCE_DELAY = 3000;
// 最小增量字数：每次备份至少要比上次新增多少字才会真正写入 localStorage
// 数字越大越省性能（酒馆越流畅），但极端崩溃时丢失的字数也越多
// 数字越小越保险（崩溃几乎不丢字），但 AI 输出时会更卡
// 建议范围：150 ~ 500，长回复/性能差的设备调大，短回复/想要保险调小
const MIN_DELTA_CHARS = 300;
const MAX_BACKUP_AGE_MS = 30 * 60 * 1000;
const PLUGIN_API = "/api/plugins/stream-guard";

let isGenerating = false;
let pollTimer = null;
let debounceTimer = null;
let lastSavedContent = "";
let serverPluginAvailable = false;
let currentGenerationChatId = "";
let currentGenerationType = "normal";
let recoveryToast = null;
let discardToast = null;

function getHeaders() {
  try {
    const h = SillyTavern.getRequestHeaders();
    if (h && h["X-CSRF-TOKEN"]) return h;
  } catch {}
  return { "Content-Type": "application/json" };
}

async function pluginGet(path) {
  try {
    return await fetch(`${PLUGIN_API}${path}`, {
      method: "GET",
      headers: getHeaders(),
      credentials: "include",
    });
  } catch {
    return null;
  }
}

async function checkServerPlugin() {
  for (let i = 0; i < 3; i++) {
    try {
      const resp = await pluginGet("/backup");
      if (resp && resp.ok) {
        serverPluginAvailable = true;
        return;
      }
      if (resp && resp.status === 404) {
        serverPluginAvailable = false;
        return;
      }
    } catch {}
    if (i < 2) await new Promise((r) => setTimeout(r, 2000));
  }
  serverPluginAvailable = false;
}

(async () => {
  await new Promise((r) => setTimeout(r, 3000));
  await checkServerPlugin();
  if (!serverPluginAvailable) {
    console.warn(
      "[StreamGuard] 服务器端插件未安装或不可用，仅使用客户端备份",
    );
  } else {
    console.log("[StreamGuard] 服务器插件与客户端脚本均已就绪");
  }
  eventOn(tavern_events.GENERATION_STARTED, onGenerationStarted);
  eventOn(tavern_events.STREAM_TOKEN_RECEIVED, onStreamToken);
  eventOn(tavern_events.GENERATION_ENDED, onGenerationFinished);
  eventOn(tavern_events.GENERATION_STOPPED, onGenerationFinished);
  await checkAndRecover();
})();

function onGenerationStarted(type, option, dry_run) {
  if (dry_run) return;
  isGenerating = true;
  lastSavedContent = "";
  currentGenerationChatId = SillyTavern.getCurrentChatId() || "";
  currentGenerationType = type || "normal";
  localStorage.setItem(STATE_KEY, "generating");
  stopPollBackup();
  pollTimer = setInterval(performBackup, POLL_INTERVAL);
  setTimeout(performBackup, 800);
}

function onStreamToken() {
  if (!isGenerating) return;
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(performBackup, DEBOUNCE_DELAY);
}

function onGenerationFinished() {
  if (!isGenerating) return;
  isGenerating = false;
  currentGenerationType = "normal";
  stopPollBackup();
  if (debounceTimer) {
    clearTimeout(debounceTimer);
    debounceTimer = null;
  }
  setTimeout(() => {
    localStorage.setItem(STATE_KEY, "idle");
    clearAllBackups();
    lastSavedContent = "";
  }, 500);
}

function stopPollBackup() {
  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
}

function performBackup() {
  if (!isGenerating) return;
  try {
    const messages = getChatMessages(-1);
    if (!messages || messages.length === 0) return;
    const lastMsg = messages[0];
    const content = lastMsg.message || "";
    if (!content.trim() || content === lastSavedContent) return;
    if (
      lastSavedContent &&
      content.length > lastSavedContent.length &&
      content.length - lastSavedContent.length < MIN_DELTA_CHARS
    ) {
      return;
    }
    lastSavedContent = content;
    localStorage.setItem(
      BACKUP_KEY,
      JSON.stringify({
        chatId:
          currentGenerationChatId || SillyTavern.getCurrentChatId() || "",
        charName: SillyTavern.name2 || "",
        messageId: lastMsg.message_id,
        name: lastMsg.name || "",
        role: lastMsg.role || "assistant",
        content: content,
        contentLength: content.length,
        timestamp: Date.now(),
        source: "client",
        generationType: currentGenerationType,
        isSwipe:
          currentGenerationType === "swipe" ||
          currentGenerationType === "regenerate",
        isContinue: currentGenerationType === "continue",
      }),
    );
  } catch (e) {
    console.error("[StreamGuard] 备份出错:", e);
  }
}

async function checkAndRecover() {
  await new Promise((r) => setTimeout(r, 1500));

  const lastState = localStorage.getItem(STATE_KEY);
  if (lastState === "idle") {
    clearAllBackups();
    localStorage.removeItem(STATE_KEY);
    return;
  }

  let clientBackup = null;
  try {
    const raw = localStorage.getItem(BACKUP_KEY);
    if (raw) clientBackup = JSON.parse(raw);
  } catch (e) {
    console.warn("[StreamGuard] 客户端备份解析失败:", e);
  }

  let serverBackup = null;
  if (serverPluginAvailable) {
    try {
      const resp = await pluginGet("/backup");
      if (resp && resp.ok) {
        const data = await resp.json();
        if (!data.empty && data.text) serverBackup = data;
      }
    } catch (e) {
      console.warn("[StreamGuard] 服务器备份获取失败:", e);
    }
  }

  let backup = null;
  let backupSource = "";

  if (clientBackup && serverBackup) {
    if (serverBackup.textLength >= clientBackup.contentLength) {
      backup = {
        chatId: clientBackup.chatId || "",
        charName: clientBackup.charName || "",
        name: clientBackup.name || "",
        role: clientBackup.role || "assistant",
        content: serverBackup.text,
        contentLength: serverBackup.textLength,
        timestamp:
          clientBackup.timestamp || serverBackup.timestamp || Date.now(),
        source: "server",
        generationType: clientBackup.generationType || "normal",
        isSwipe: clientBackup.isSwipe || false,
        isContinue: clientBackup.isContinue || false,
      };
      backupSource = `服务器端(${serverBackup.textLength}字)`;
    } else {
      backup = clientBackup;
      backupSource = `客户端(${clientBackup.contentLength}字)`;
    }
  } else if (serverBackup) {
    backup = {
      chatId: "",
      charName: "",
      name: "",
      role: "assistant",
      content: serverBackup.text,
      contentLength: serverBackup.textLength,
      timestamp: serverBackup.timestamp,
      source: "server",
      generationType: "normal",
      isSwipe: false,
      isContinue: false,
    };
    backupSource = `服务器端(${serverBackup.textLength}字)`;
  } else if (clientBackup) {
    backup = clientBackup;
    backupSource = serverPluginAvailable
      ? `客户端(${clientBackup.contentLength}字) - 服务器端未捕获到流数据`
      : `客户端(${clientBackup.contentLength}字) - 服务器插件未安装`;
  }

  if (!backup) {
    localStorage.removeItem(STATE_KEY);
    return;
  }

  if (Date.now() - (backup.timestamp || 0) > MAX_BACKUP_AGE_MS) {
    clearAllBackups();
    localStorage.removeItem(STATE_KEY);
    return;
  }

  if (!backup.content || !backup.content.trim()) {
    clearAllBackups();
    localStorage.removeItem(STATE_KEY);
    return;
  }

  if (isContentInChat(backup.content)) {
    clearAllBackups();
    localStorage.removeItem(STATE_KEY);
    return;
  }

  console.log(`[StreamGuard] 📦 发现可恢复备份: ${backupSource}`);
  showRecoveryUI(backup, backupSource);
}

function isContentInChat(content) {
  try {
    const lastId = getLastMessageId();
    if (lastId < 0) return false;
    const start = Math.max(0, lastId - 3);
    const msgs = getChatMessages(`${start}-${lastId}`);
    if (!msgs || msgs.length === 0) return false;
    const snippet = content.trim().substring(0, 100);
    if (!snippet) return false;
    for (const msg of msgs) {
      if (msg.message && msg.message.includes(snippet)) {
        if (msg.message.length >= content.length) return true;
      }
    }
  } catch (e) {
    console.warn("[StreamGuard] isContentInChat 出错:", e);
  }
  return false;
}

function dismissAllToasts() {
  if (recoveryToast) {
    toastr.clear(recoveryToast);
    recoveryToast = null;
  }
  if (discardToast) {
    toastr.clear(discardToast);
    discardToast = null;
  }
}

function getRecoveryTypeLabel(backup) {
  if (backup.isSwipe) return "备选回复(Swipe)";
  if (backup.isContinue) return "续写(Continue)";
  return "新消息";
}

function showRecoveryUI(backup, backupSource) {
  const minutesAgo = Math.max(
    1,
    Math.ceil((Date.now() - backup.timestamp) / 60000),
  );
  const preview =
    backup.content.length > 150
      ? backup.content.substring(0, 150) + "..."
      : backup.content;
  const typeLabel = getRecoveryTypeLabel(backup);

  const recoveryMsg =
    `${minutesAgo}分钟前的回复 | ${backup.name || "未知"} | ${backup.contentLength}字 | ${typeLabel}\n` +
    `来源: ${backupSource}\n` +
    `${preview}\n\n` +
    `<i class="fa-solid fa-arrow-pointer"></i> 点击恢复到聊天`;

  recoveryToast = toastr.warning(
    recoveryMsg,
    '<i class="fa-solid fa-shield-halved"></i> StreamGuard 发现未保存回复',
    {
      timeOut: 0,
      extendedTimeOut: 0,
      closeButton: true,
      escapeHtml: false,
      onclick: async () => {
        dismissAllToasts();
        await doRecover(backup, backupSource);
      },
    },
  );

  discardToast = toastr.info(
    '<i class="fa-solid fa-arrow-pointer"></i> 点击丢弃备份',
    '<i class="fa-solid fa-trash-can"></i> 不需要恢复？',
    {
      timeOut: 0,
      extendedTimeOut: 0,
      closeButton: true,
      escapeHtml: false,
      onclick: () => {
        dismissAllToasts();
        clearAllBackups();
        localStorage.removeItem(STATE_KEY);
        toastr.success(
          "备份已丢弃",
          '<i class="fa-solid fa-check"></i> 完成',
          { escapeHtml: false },
        );
      },
    },
  );
}

async function doRecover(backup, backupSource) {
  try {
    if (backup.isSwipe) {
      const lastMsgs = getChatMessages(-1, { include_swipes: true });
      if (lastMsgs && lastMsgs.length > 0) {
        const lastMsg = lastMsgs[0];
        const newSwipes = [...(lastMsg.swipes || [])];
        const newSwipesData = [...(lastMsg.swipes_data || [])];
        const newSwipesInfo = [...(lastMsg.swipes_info || [])];
        newSwipes.push(backup.content);
        newSwipesData.push({});
        newSwipesInfo.push({});
        await setChatMessages([
          {
            message_id: lastMsg.message_id,
            swipes: newSwipes,
            swipes_data: newSwipesData,
            swipes_info: newSwipesInfo,
            swipe_id: newSwipes.length - 1,
          },
        ]);
        clearAllBackups();
        localStorage.removeItem(STATE_KEY);
        toastr.success(
          `恢复成功 - 已作为备选回复添加 (${backup.contentLength}字, ${backupSource})`,
          '<i class="fa-solid fa-check"></i> StreamGuard',
          { escapeHtml: false },
        );
      } else {
        await fallbackRecover(backup, backupSource);
      }
    } else if (backup.isContinue) {
      const lastMsgs = getChatMessages(-1);
      if (lastMsgs && lastMsgs.length > 0) {
        await setChatMessages([
          {
            message_id: lastMsgs[0].message_id,
            message: backup.content,
          },
        ]);
        clearAllBackups();
        localStorage.removeItem(STATE_KEY);
        toastr.success(
          `恢复成功 - 已续写到最后一条消息 (${backup.contentLength}字, ${backupSource})`,
          '<i class="fa-solid fa-check"></i> StreamGuard',
          { escapeHtml: false },
        );
      } else {
        await fallbackRecover(backup, backupSource);
      }
    } else {
      await fallbackRecover(backup, backupSource);
    }
  } catch (e) {
    console.error("[StreamGuard] 恢复出错:", e);
    try {
      builtin.copyText(backup.content);
      toastr.warning(
        "已复制到剪贴板，请手动粘贴",
        '<i class="fa-solid fa-clipboard"></i> 恢复失败',
        { escapeHtml: false },
      );
    } catch {
      toastr.error(
        "F12控制台查看内容",
        '<i class="fa-solid fa-triangle-exclamation"></i> 恢复失败',
        { escapeHtml: false },
      );
    }
  }
}

async function fallbackRecover(backup, backupSource) {
  await createChatMessages([
    {
      role: backup.role || "assistant",
      name:
        backup.name || backup.charName || SillyTavern.name2 || "Assistant",
      message: backup.content,
    },
  ]);
  clearAllBackups();
  localStorage.removeItem(STATE_KEY);
  toastr.success(
    `恢复成功 (${backup.contentLength}字, ${backupSource})`,
    '<i class="fa-solid fa-check"></i> StreamGuard',
    { escapeHtml: false },
  );
}

function clearAllBackups() {
  localStorage.removeItem(BACKUP_KEY);
  if (serverPluginAvailable) {
    pluginGet("/clear").catch(() => {});
  }
}
